<script lang="ts">let {data}=$props();</script><div class="hero"><div><h1>Match comparison</h1><div class="muted">Twizzit availability beside official Sportlink participation.</div></div></div><div class="table-wrap"><table><thead><tr><th>Date</th><th>Fixture</th><th>Side</th><th>Opponent</th><th>Twizzit</th><th>Sportlink</th><th></th></tr></thead><tbody>{#each data.rows as m}<tr><td>{new Date(`${m.date}T12:00`).toLocaleDateString('en-BE')}</td><td>{m.name}</td><td>{m.side??'unknown'}</td><td>{m.opponent??'unknown'}</td><td>{m.twizzitScorable?'loaded':'missing / failed'}</td><td>{m.sportlinkScorable?'loaded':'missing'}</td><td><a href="/matches/{m.id}?dataset={data.datasetId}">Compare players →</a></td></tr>{/each}</tbody></table></div>
